var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네~","JPN":"モネネ～","ENG":"Monene!","TWN":"莫妮妮～"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 제가 지금 더위라도 먹은 건가요?","JPN":"社長、今の私は熱中症にでもなっているのでしょうか？","ENG":"Boss, am I suffering from heat stroke?","TWN":"老闆，我是中暑產生幻覺嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 그건 아닌 것 같군. 내 카메라에도 저 미지의 생명체들이 선명하게 찍히고 있어.","JPN":"いや、違うな。私のカメラにもあの未知の生命体が鮮明に写っている。","ENG":"Um, I don’t think so. I’m seeing these mysterious creatures on my camera as well.","TWN":"嗯，好像不是欸。我的相機有清楚拍到那些謎樣生物。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"침식파는 감지되지 않아. 어쩌면 다른 세상에서 온 엑자일러일지도 모르겠군.","JPN":"侵食波は感知されない。もしかしたら他の世界から来たエグザイラーの可能性もあるな。","ENG":"I’m not sensing any Corruption Rays. Maybe they’re Exiles from another world.","TWN":"通常侵蝕波是不會感應到的，可能是來自另一個世界的流浪者。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"위험해 보이진 않으니 잘 설득하면 평화롭게 돌려보낼 수 있을지도 모르네.","JPN":"危険そうにはみえないから、ちゃんと説得すればトラブルなく帰ってくれるかもしれない。","ENG":"They don’t seem dangerous. Maybe we can persuade them to go back where they came from.","TWN":"看起來沒什麼危險性，只要好言相勸，說不定可以和平地把他們送走。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"상대는 펭귄 비슷한 무언가입니다. 말처럼 쉽게 풀리진 않을 텐데요.","JPN":"相手はペンギンに似ている何かです。言うのは簡単ですが上手くいくとは限りません。","ENG":"They look like penguins. I don’t think we can talk to them.","TWN":"對方是類似企鵝的東西，應該沒那麼好說話。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후. 걱정도 많군. 숱한 연봉 협상으로 단련된 내 말솜씨를 믿게나.","JPN":"フフ、心配性だな。数多くの年俸交渉で鍛えられた私の話術を信じてくれ。","ENG":"Hah hah, don’t worry about it. I’ve been through countless Salary Negotiations, trust me.","TWN":"呵呵，副總多慮囉！我可是談過無數次薪資協商呢！你就相信我的談判技巧吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"반갑네, 작은 친구들! 내가 아는 견습 메이드와 꼭 닮았군!","JPN":"やあ、おチビさんたち！　私の知っている見習いメイドにそっくりだな！","ENG":"Hello, little friends! You look just like a maid-in-training I know!","TWN":"哈囉，小朋友們！你們長得很像我認識的見習女僕欸！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우린 자네들과 싸울 생각이 전혀 없다네. 그러니 대화로 풀어나가 보면 어떻겠나.","JPN":"我々は君たちと戦うつもりなどまったくない。だから会話で解決しようじゃないか。","ENG":"We don’t want to fight you. How about we talk this out?","TWN":"我們沒有想要傷害你們的意思，君子動口不動手。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네…….","JPN":"モネ……","ENG":"Mone...","TWN":"莫妮…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이, 이보게들? 왜 갑자기 붙잡는 건가?","JPN":"な、なんだ！？　私を捕まえて何をするつもりだ？","ENG":"Um, hey? Why are you grabbing me?","TWN":"喂，你們幹嘛突然抓著我？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우리 지성인들답게 말로 해결하세나. 날 바다에 던진다고 해결되는 건……","JPN":"知性人らしく会話で解決しよう。私を海に投げても何も解決しな……","ENG":"Please, let’s talk this out as civilized people. Throwing me to the sea won’t solve—","TWN":"大家有話好好說，把我扔到海裡不會解决…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네!","JPN":"モネネ！","ENG":"Monene!","TWN":"莫妮妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모~네!","JPN":"モ～ネ！","ENG":"Mo-ne!","TWN":"莫～妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우앗?! 펭귄들이 고객님을 바다에 던져 버렸어요!","JPN":"わっ！？　ペンギンたちがお客様を海に投げ落としました！","ENG":"Heek! Those penguins threw my client to the sea!","TWN":"哇？！企鵝們把客人扔進海裡咧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우오오! 떠내려간다! 떠내려가!","JPN":"うおおお！　流されるぞ！　流されていくううう！","ENG":"Gah! I’m drifting! I’m drifting away!","TWN":"嗚嗚嗚！要被沖走了啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"사모님! 저대로 두면 넓은 바다로 고객님이 떠내려 가시겠어요!","JPN":"奥様！　あのままだと広い海にお客様が流されてしまいます！","ENG":"Missus! He will drift off into the open sea if we don’t help him!","TWN":"老闆娘！再不救他的話，他就要漂到太平洋囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아무래도 저 펭귄들은 협상 테이블에 앉기 싫은가 보군요.","JPN":"どうやらあのペンギンたちは話し合いに応じそうにないですね。","ENG":"It looks like these penguins don’t want to negotiate.","TWN":"看來那些企鵝沒有想談的意思。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님은 제가 건져 오겠습니다. 당신은 그동안 저들이 방해 못 하게 막아 주세요.","JPN":"社長は私が拾ってきます。あなたはその間、あのペンギンたちが邪魔してこないように止めてください。","ENG":"I’ll go bring him back. Meanwhile, you stop them from interrupting me.","TWN":"我去把老闆打撈回來，那些企鵝就交給你，請不要讓那些企鵝來妨礙我。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네?! 전 배달부지 용병이 아닌데요! 사모님!?","JPN":"え！？　私は普通の配達員で傭兵ではありませんよ、奥様！？","ENG":"What?! I’m a deliverywoman, not a mercenary, missus!","TWN":"嗯？！我是送貨員不是傭兵欸！老闆娘！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네네~!","JPN":"モネネネ～！","ENG":"Monenene!","TWN":"莫妮妮妮～！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"옴마야아아아!","JPN":"キャアアアァァァ！","ENG":"Argh!","TWN":"呃啊啊啊啊啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};